<?php $adminTitle='LMS Settings'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ if(($_POST['form']??'')==='category'){ $pdo->prepare('INSERT INTO lms_categories (name,slug,description,status) VALUES (?,?,?,?) ON DUPLICATE KEY UPDATE description=VALUES(description),status=VALUES(status)')->execute([trim($_POST['name']),slugify($_POST['name']),trim($_POST['description']),$_POST['status']]); } else { $pdo->prepare('INSERT INTO lms_settings (setting_key,setting_value) VALUES (?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)')->execute([trim($_POST['setting_key']),trim($_POST['setting_value'])]); } header('Location: lms-settings.php'); exit; } $cats=$pdo->query('SELECT * FROM lms_categories ORDER BY name')->fetchAll(); $settings=$pdo->query('SELECT * FROM lms_settings ORDER BY setting_key')->fetchAll(); ?><h1>LMS Settings & Categories</h1><div class="row g-4"><div class="col-lg-6"><form class="glass-card" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><input type="hidden" name="form" value="category"><h2>Add Course Category</h2><label>Name</label><input class="form-control mb-3" name="name" required><label>Description</label><textarea class="form-control mb-3" name="description"></textarea><label>Status</label><select class="form-select mb-3" name="status"><option>active</option><option>inactive</option></select><button class="btn btn-premium">Save Category</button></form></div><div class="col-lg-6"><form class="glass-card" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><h2>LMS Setting</h2><label>Key</label><input class="form-control mb-3" name="setting_key" required><label>Value</label><textarea class="form-control mb-3" name="setting_value" required></textarea><button class="btn btn-premium">Save Setting</button></form></div></div><div class="row g-4 mt-1"><div class="col-lg-6"><div class="glass-card"><h2>Categories</h2><?php foreach($cats as $c): ?><p><strong><?= e($c['name']); ?></strong> - <?= e($c['status']); ?></p><?php endforeach; ?></div></div><div class="col-lg-6"><div class="glass-card"><h2>Settings</h2><?php foreach($settings as $s): ?><p><strong><?= e($s['setting_key']); ?></strong>: <?= e($s['setting_value']); ?></p><?php endforeach; ?></div></div></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>